fixed_code:
fn main() {
    let mut user = User { name: String::from("Alice"), age: 30 };

    // Split borrows safely to avoid panic
    let name_ref = &user.name;
    let age_ref = unsafe { &mut *(&mut user.age as *mut u8) };

    println!("Name: {}, Age: {}", name_ref, *age_ref);
}
struct User {
    name: String,
    age: u8,
}
